import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";
import { useGetAllProductsQuery } from "../../slices/productsApi";
import Form from "../pages/Forms";
const Login = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [remember, setRemember] = useState(false);
  const [validate, setValidate] = useState({});
  const [showPassword, setShowPassword] = useState(false);
  const [errorMessages, setErrorMessages] = useState({});
  const [isSubmitted, setIsSubmitted] = useState(false);



  // const handleLogin = async () =>{
  //   console.log("email,password",email,password)
  //   let result = await fetch('http://localhost:1313/login',{
  //     method:'post',
  //     body:JSON.stringify({email,password}),
  //     headers:{
  //       'Content-Type': 'application/json'
  //     }
  //   });
  //   result = await result.json();
  //   console.log(result)
  //   if(result.email){
  //     localStorage.setItem("user",JSON.stringify(result));
  //     Navigate("/home")

  //   }else{
  //     alert("invalid")
  //   }
  // }
  const renderErrorMessage = (name) =>
    name === errorMessages.name && (
      <div className="error">{errorMessages.message}</div>
    );
    // const onSubmit = () => {
    //   return axios
    //     .post("http://localhost:1313/login", {
    //       email,
    //       password,
    //     })
    //     .then((response) => {
    //       // if (response.data.username) {
    //       //   localStorage.setItem("user", JSON.stringify(response.data));
    //       // }
    //       console.log(response);
    //       return false;
    //       return response.data;
    //     });
    // };
    const data = {
     
      email: email,
      password: password,

      // other fields...
    };
   
    //     e.preventDefault();
    
    //     const response1 = await fetch("http://localhost:1313/login", {
    //       method: "POST",
    //       headers: {
    //         "Content-Type": "application/json",
    //       },
    //       body: JSON.stringify({ email, password }),
          
    //     });
        
    //     if (response1.status !== 200) {
    //       return alert("Something went wrong");
    //     }
    //    // Navigate("/home");
    //     console.log(response1);
    // return false;
    
    const validateLogin = () => {
      let isValid = true;
      let validator = Form.validator({
      email: {
        value: email,
        isRequired: true,
        isEmail: true,
      },
      password: {
        value: password,
        isRequired: true,
        minLength: 6,
      },
    });
    
    if (validator !== null) {
      setValidate({
        validate: validator.errors,
      });
      
      isValid = false;
    }
    return isValid;
  };

  const Navigate = useNavigate();
  const authenticate = async(e) => {
    e.preventDefault();
     {
  axios
  .post("http://localhost:1313/login", data)
  
  .then((res) => {
    
    if(!success){
      //handle errors here
      console.log(res.message)
      return;
  }

  // handle successful requests here
  console.log(res.message)

    console.log(res.data);
    return false;
  })
  .catch((error) => {
    console.log(error);
  });
  return false;
    };
    
    const validate = validateLogin();

    if (validate) {
      setValidate({});
      setEmail("");
      setPassword("");
      Navigate("/home");
    }
  };

  const togglePassword = (e) => {
    if (showPassword) {
      setShowPassword(false);
    } else {
      setShowPassword(true);
    }
  };



  return (
    // <div className="col-12 col-md-7 col-lg-6 auth-main-col text-center">
    <div className="d-flex flex-column align-content-end">
      <div className="auth-body mx-auto">
        <h2>Login to your account</h2>
        <div className="auth-form-container text-start">
          <form
            className="auth-form"
            method="POST"
            // onSubmit={onSubmit}
            autoComplete={"off"}
          >
            <div className="email mb-3">
              <input
                type="email"
                className={`form-control ${
                  validate.validate && validate.validate.email
                    ? "is-invalid "
                    : ""
                }`}
                id="email"
                name="email"
                value={email}
                placeholder="Email"
                onChange={(e) => setEmail(e.target.value)}
              />
              {renderErrorMessage("email")}

              <div
                className={`invalid-feedback text-start ${
                  validate.validate && validate.validate.email
                    ? "d-block"
                    : "d-none"
                }`}
              >
                {validate.validate && validate.validate.email
                  ? validate.validate.email[0]
                  : ""}
              </div>
            </div>

            <div className="password mb-3">
              <div className="input-group">
                <input
                  type={showPassword ? "text" : "password"}
                  className={`form-control ${
                    validate.validate && validate.validate.password
                      ? "is-invalid "
                      : ""
                  }`}
                  name="password"
                  id="password"
                  value={password}
                  placeholder="Password"
                  onChange={(e) => setPassword(e.target.value)}
                />
                {renderErrorMessage("password")}

                <button
                  type="button"
                  className="btn btn-outline-primary btn-sm"
                  onClick={(e) => togglePassword(e)}
                >
                  <i
                    className={showPassword ? "far fa-eye" : "far fa-eye-slash"}
                  ></i>{" "}
                </button>

                <div
                  className={`invalid-feedback text-start ${
                    validate.validate && validate.validate.password
                      ? "d-block"
                      : "d-none"
                  }`}
                >
                  {validate.validate && validate.validate.password
                    ? validate.validate.password[0]
                    : ""}
                </div>
              </div>

              <div className="extra mt-3 row justify-content-between">
                <div className="col-6">
                  <div className="form-check">
                    <input
                      className="form-check-input"
                      type="checkbox"
                      id="remember"
                      checked={remember}
                      onChange={(e) => setRemember(e.currentTarget.checked)}
                    />
                    <label className="form-check-label" htmlFor="remember">
                      Remember me
                    </label>
                  </div>
                </div>
                <div className="col-6">
                  <div className="forgot-password text-end">
                    <Link to="/forgot">Forgot password?</Link>
                  </div>
                </div>
              </div>
            </div>
            <div className="text-center">
              <button
                type="button"
                className="btn btn-primary w-100 theme-btn mx-auto"
                onClick={authenticate}
              >
                Log In
              </button>
            </div>
          </form>

          <hr />
          <div className="auth-option text-center pt-2">
            No Account?{" "}
            <Link className="text-link" to="/regi">
              Sign up{" "}
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
